// src/lib/comprovante-pdf.ts
import { jsPDF } from 'jspdf'

interface ReceiptData {
  distribution: {
    id: string
    date: string
    beneficiary: { name: string; address: string | null } | null
    items: {
      id: string
      quantity: number
      boxes: number | null
      product: { name: string; unit: string }
    }[]
  }
  receipt: {
    recipientName: string
    signatureData: string
    notes: string | null
    finalizedAt: string
    finalizedBy: { name: string | null; email: string | null } | null
  }
}

// 🖼️ Cole aqui a string base64 da logo (data:image/png;base64,iVBOR...).
// Enquanto estiver vazia, o PDF é gerado SEM logo (protegido por try/catch).
const LOGO_BASE64 = 'data:image/png;base64,'

function formatDate(date: string): string {
  const raw = date.includes('T') ? date.split('T')[0] : date
  const [year, month, day] = raw.split('-')
  return `${day}/${month}/${year}`
}

function formatDateTime(date: string): string {
  const d = new Date(date)
  return d.toLocaleString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  })
}

/**
 * Gera e dispara o download do comprovante de entrega em PDF.
 * A assinatura (PNG base64) é embutida via addImage.
 */
export function gerarComprovantePDF(data: ReceiptData) {
  const { distribution, receipt } = data
  const doc = new jsPDF({ unit: 'mm', format: 'a4' })

  const pageWidth = doc.internal.pageSize.getWidth()
  const marginX = 20
  let y = 20

  // 🟢 Cabeçalho — logo + identidade
  const logoSize = 14 // mm
  let textX = marginX // posição X do texto (deslocada se houver logo)

  if (LOGO_BASE64) {
    try {
      doc.addImage(LOGO_BASE64, 'PNG', marginX, y - 4, logoSize, logoSize)
      textX = marginX + logoSize + 4
    } catch {
      textX = marginX
    }
  }

  doc.setFontSize(18)
  doc.setTextColor(22, 163, 74) // green-600
  doc.setFont('helvetica', 'bold')
  doc.text('Annonae', textX, y)

  doc.setFontSize(9)
  doc.setTextColor(107, 114, 128) // gray-500
  doc.setFont('helvetica', 'normal')
  doc.text('Banco de Alimentos de São João del-Rei', textX, y + 5)

  doc.setFontSize(14)
  doc.setTextColor(31, 41, 55) // gray-800
  doc.setFont('helvetica', 'bold')
  doc.text('Comprovante de Entrega', pageWidth - marginX, y, {
    align: 'right',
  })

  y += 15
  doc.setDrawColor(220, 220, 220)
  doc.line(marginX, y, pageWidth - marginX, y)
  y += 10

  // 📋 Dados da distribuição
  doc.setFontSize(11)
  doc.setTextColor(31, 41, 55)
  doc.setFont('helvetica', 'bold')
  doc.text('Instituição beneficiária', marginX, y)
  y += 6

  doc.setFont('helvetica', 'normal')
  doc.setTextColor(55, 65, 81)
  doc.text(distribution.beneficiary?.name ?? '—', marginX, y)
  y += 5

  if (distribution.beneficiary?.address) {
    doc.setFontSize(9)
    doc.setTextColor(107, 114, 128)
    doc.text(distribution.beneficiary.address, marginX, y)
    y += 5
  }

  doc.setFontSize(10)
  doc.setTextColor(55, 65, 81)
  doc.text(`Data da entrega: ${formatDate(distribution.date)}`, marginX, y)
  y += 10

  // 📦 Itens
  doc.setFontSize(11)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(31, 41, 55)
  doc.text('Itens entregues', marginX, y)
  y += 7

  doc.setFontSize(9)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(107, 114, 128)
  doc.text('Produto', marginX, y)
  doc.text('Quantidade', pageWidth - marginX - 50, y)
  doc.text('Caixas', pageWidth - marginX, y, { align: 'right' })
  y += 2
  doc.setDrawColor(235, 235, 235)
  doc.line(marginX, y, pageWidth - marginX, y)
  y += 5

  doc.setFont('helvetica', 'normal')
  doc.setTextColor(55, 65, 81)
  distribution.items.forEach((item) => {
    doc.text(item.product.name, marginX, y)
    doc.text(
      `${item.quantity} ${item.product.unit}`,
      pageWidth - marginX - 50,
      y,
    )
    doc.text(item.boxes ? `${item.boxes}` : '—', pageWidth - marginX, y, {
      align: 'right',
    })
    y += 6
  })

  y += 8

  // ✍️ Assinatura
  doc.setFontSize(11)
  doc.setFont('helvetica', 'bold')
  doc.setTextColor(31, 41, 55)
  doc.text('Confirmação de recebimento', marginX, y)
  y += 8

  // Caixa da assinatura
  const sigBoxW = 80
  const sigBoxH = 35
  try {
    doc.setDrawColor(200, 200, 200)
    doc.rect(marginX, y, sigBoxW, sigBoxH)
    doc.addImage(
      receipt.signatureData,
      'PNG',
      marginX + 2,
      y + 2,
      sigBoxW - 4,
      sigBoxH - 4,
    )
  } catch {
    doc.setFontSize(9)
    doc.setTextColor(150, 150, 150)
    doc.text('[assinatura indisponível]', marginX + 4, y + sigBoxH / 2)
  }

  y += sigBoxH + 5
  doc.setFontSize(10)
  doc.setFont('helvetica', 'normal')
  doc.setTextColor(55, 65, 81)
  doc.text(`Recebido por: ${receipt.recipientName}`, marginX, y)
  y += 6

  if (receipt.notes) {
    doc.setFontSize(9)
    doc.setTextColor(107, 114, 128)
    const noteLines = doc.splitTextToSize(
      `Obs.: ${receipt.notes}`,
      pageWidth - marginX * 2,
    )
    doc.text(noteLines, marginX, y)
    y += noteLines.length * 5
  }

  // 🔒 Rodapé de auditoria
  y += 6
  doc.setDrawColor(220, 220, 220)
  doc.line(marginX, y, pageWidth - marginX, y)
  y += 6

  doc.setFontSize(8)
  doc.setTextColor(150, 150, 150)
  doc.text(
    `Finalizado por ${receipt.finalizedBy?.name ?? '—'} em ${formatDateTime(
      receipt.finalizedAt,
    )}`,
    marginX,
    y,
  )
  doc.text(`ID: ${distribution.id}`, pageWidth - marginX, y, {
    align: 'right',
  })

  // 💾 Download
  const fileName = `comprovante-${distribution.beneficiary?.name
    ?.toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9-]/g, '') ?? 'entrega'}-${formatDate(
    distribution.date,
  ).replace(/\//g, '-')}.pdf`

  doc.save(fileName)
}
